CREATE TABLE "Case" (id TEXT PRIMARY KEY, tenantId TEXT NOT NULL, branchId TEXT, caseNumber TEXT NOT NULL, subject TEXT NOT NULL, description TEXT, status TEXT DEFAULT 'OPEN', priority TEXT DEFAULT 'MEDIUM', channelId TEXT, typeId TEXT, groupId TEXT, clientId TEXT, assignedToId TEXT, createdById TEXT, createdAt TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updatedAt TIMESTAMP DEFAULT CURRENT_TIMESTAMP, deletedAt TIMESTAMP); CREATE UNIQUE INDEX Case_tenantId_caseNumber_key ON "Case"(tenantId,caseNumber); CREATE INDEX Case_tenantId_idx ON "Case"(tenantId); CREATE INDEX Case_clientId_idx ON "Case"(clientId); CREATE INDEX Case_status_idx ON "Case"(status); ALTER TABLE "Case" ADD CONSTRAINT Case_clientId_fkey FOREIGN KEY (clientId) REFERENCES "Client"(id) ON DELETE SET NULL; ALTER TABLE "Case" ADD CONSTRAINT Case_channelId_fkey FOREIGN KEY (channelId) REFERENCES "CaseChannel"(id) ON DELETE SET NULL; ALTER TABLE "Case" ADD CONSTRAINT Case_typeId_fkey FOREIGN KEY (typeId) REFERENCES "CaseType"(id) ON DELETE SET NULL; ALTER TABLE "Case" ADD CONSTRAINT Case_groupId_fkey FOREIGN KEY (groupId) REFERENCES "CaseGroup"(id) ON DELETE SET NULL; ALTER TABLE "Case" ADD CONSTRAINT Case_assignedToId_fkey FOREIGN KEY (assignedToId) REFERENCES "User"(id) ON DELETE SET NULL; CREATE TABLE "CaseReply" (id TEXT PRIMARY KEY, tenantId TEXT NOT NULL, caseId TEXT NOT NULL, message TEXT NOT NULL, isInternal BOOLEAN DEFAULT false, createdById TEXT, createdAt TIMESTAMP DEFAULT CURRENT_TIMESTAMP); CREATE INDEX CaseReply_tenantId_idx ON "CaseReply"(tenantId); CREATE INDEX CaseReply_caseId_idx ON "CaseReply"(caseId); ALTER TABLE "CaseReply" ADD CONSTRAINT CaseReply_caseId_fkey FOREIGN KEY (caseId) REFERENCES "Case"(id) ON DELETE CASCADE; CREATE TABLE "CaseChannel" (id TEXT PRIMARY KEY, tenantId TEXT NOT NULL, name TEXT NOT NULL, code TEXT NOT NULL, isActive BOOLEAN DEFAULT true, createdAt TIMESTAMP DEFAULT CURRENT_TIMESTAMP); CREATE UNIQUE INDEX CaseChannel_tenantId_code_key ON "CaseChannel"(tenantId,code); CREATE INDEX CaseChannel_tenantId_idx ON "CaseChannel"(tenantId); CREATE TABLE "CaseType" (id TEXT PRIMARY KEY, tenantId TEXT NOT NULL, name TEXT NOT NULL, code TEXT NOT NULL, isActive BOOLEAN DEFAULT true, createdAt TIMESTAMP DEFAULT CURRENT_TIMESTAMP); CREATE UNIQUE INDEX CaseType_tenantId_code_key ON "CaseType"(tenantId,code); CREATE INDEX CaseType_tenantId_idx ON "CaseType"(tenantId); CREATE TABLE "CaseGroup" (id TEXT PRIMARY KEY, tenantId TEXT NOT NULL, name TEXT NOT NULL, code TEXT NOT NULL, isActive BOOLEAN DEFAULT true, createdAt TIMESTAMP DEFAULT CURRENT_TIMESTAMP); CREATE UNIQUE INDEX CaseGroup_tenantId_code_key ON "CaseGroup"(tenantId,code); CREATE INDEX CaseGroup_tenantId_idx ON "CaseGroup"(tenantId);
